class MobileLivePreview {
 private static $instance = null;
 public static function get_instance() {
if (null === self::$instance) {
 self::$instance = new self();
}
return self::$instance;
 }
 private function __construct() {
// Always needed (rewrite endpoint + option cache invalidation).
add_action('init', array($this, 'init'));
add_action('init', array($this, 'add_share_endpoint'));
// Invalidate option caches whenever any setting is saved.
foreach ( array(
 'mlp_default_height', 'mlp_default_title', 'mlp_default_theme',
 'mlp_editor_theme', 'mlp_default_html', 'mlp_default_css', 'mlp_default_js',
) as $_mlp_opt ) {
 add_action( 'update_option_' . $_mlp_opt, array( $this, 'invalidate_options_cache' ) );
}
unset($_mlp_opt);

// AJAX handlers — register only during AJAX requests.
// NOTE: We must NOT return early here because wp_ajax_* actions fire inside
// wp-admin/admin-ajax.php which also sets is_admin()=true. If we returned early
// the nonce localization and media enqueue hooks would never run, causing every
// AJAX call to receive an HTML login page instead of JSON (the
// "Unexpected token '<', <!DOCTYPE" error).
if ( defined('DOING_AJAX') && DOING_AJAX ) {
 add_action('wp_ajax_mlp_imgcdn_proxy',         array($this, 'ajax_imgcdn_proxy'));
 // nopriv removed — handler already requires manage_options; exposing the hook wastes a WP bootstrap per bot hit.
 add_action('wp_ajax_mlp_get_templates',        array($this, 'ajax_get_templates'));
 add_action('wp_ajax_nopriv_mlp_get_templates', array($this, 'ajax_get_templates'));
 add_action('wp_ajax_mlp_save_template',        array($this, 'ajax_save_template'));
 add_action('wp_ajax_mlp_delete_template',      array($this, 'ajax_delete_template'));
 // Do NOT return — localize_ajax_vars must also run so the nonce is available.
}

// Admin-only hooks (settings page, notices, rewrite check).
// NOTE: We must NOT return early here either. The WP media upload popup runs in
// an admin context (is_admin()=true) but still needs wp_enqueue_media and the
// localize_ajax_vars nonce to work. An early return here breaks the media
// category/insert popup entirely.
if ( is_admin() ) {
 add_action('admin_menu',    array($this, 'create_settings_page'));
 add_action('admin_init',    array($this, 'register_settings'));
 add_action('admin_notices', array($this, 'admin_notice_openssl_check'));
 add_action('admin_post_mlp_rotate_enc_key', array($this, 'handle_rotate_enc_key_request'));
 add_action('init',          array($this, 'check_rewrite_rules'));
 // Still register the nonce localizer so AJAX calls from the media popup work.
 add_action('admin_enqueue_scripts', array($this, 'localize_ajax_vars'));
 return; // Frontend script/shortcode hooks not needed in wp-admin.
}

// Frontend-only hooks.
add_shortcode('mobile_live_preview', array($this, 'shortcode'));
// Consolidate all frontend enqueue actions into ONE hook call to avoid
// WordPress firing 4 separate hook passes (each has its own priority-queue walk).
add_action('wp_enqueue_scripts', array($this, 'frontend_enqueue_all'), 10);
add_action('template_redirect',  array($this, 'handle_share_url'));
// Projects popup — full-page overlay shown before the editor loads.
MLP_Projects::init();
 }
 public function admin_notice_openssl_check() {}
 public function handle_rotate_enc_key_request() { wp_die('Disabled.'); }
 public function add_user_status_script() {
global $post;
if (is_a($post, 'WP_Post') && has_shortcode($post->post_content, 'mobile_live_preview')) {
 wp_localize_script('jquery', 'mlp_user', array(
    'is_admin' => current_user_can('manage_options')
 ));
}
 }
 /**
  * Single wp_enqueue_scripts callback that replaces the four separate hooks
  * (enqueue_scripts, localize_ajax_vars, add_user_status_script, output_javascript).
  * Consolidating into one pass saves three extra priority-queue iterations per page load.
  */
 public function frontend_enqueue_all() {
$this->enqueue_scripts();
$this->localize_ajax_vars();
$this->add_user_status_script();
$this->output_javascript();
 }
 public function check_rewrite_rules() {
if ( ! is_admin() ) {
 return;
}
// Avoid repeated expensive flush_rewrite_rules() calls — check at most once per hour.
if ( get_transient( 'mlp_rewrite_checked' ) ) {
 return;
}
set_transient( 'mlp_rewrite_checked', 1, HOUR_IN_SECONDS );
$rules = get_option('rewrite_rules');
if (!isset($rules['^mlp-share/([^/]+)/?$'])) {
 flush_rewrite_rules();
}
 }
 public function init() {
load_plugin_textdomain('mobile-live-preview', false, dirname(plugin_basename(__FILE__)) . '/languages/');
 }
 public function localize_ajax_vars() {
$data = array(
   'ajaxurl'  => admin_url('admin-ajax.php'),
   'nonce'    => wp_create_nonce('mlp_ajax_nonce'),
   'home_url' => home_url(),
);
// wp_localize_script() requires a registered/enqueued script as its handle.
// jQuery is always present on the frontend; in admin (e.g. media popup) we
// output a direct inline <script> as a reliable fallback so mlp_ajax is
// always defined regardless of which script is or isn't enqueued.
if ( wp_script_is('jquery', 'enqueued') || wp_script_is('jquery', 'registered') ) {
 wp_localize_script('jquery', 'mlp_ajax', $data);
} else {
 // Inline fallback — safe because mlp_ajax values contain no user input.
 add_action( is_admin() ? 'admin_head' : 'wp_head', function() use ( $data ) {
  echo '<script>window.mlp_ajax=' . wp_json_encode($data) . ';</script>' . "
";
 }, 1 );
}
 }
 const MAX_CODE_BYTES = 524288;
 const MAX_SHARE_BYTES = 131072;
 const SHARE_RATE_LIMIT = 30;
 const SHARE_TABLE_MAX_ROWS = 100000;
 const RL_CACHE_TTL = 65;
 const DAILY_CAP_CACHE_TTL = 120;
 const ANOMALY_LOG_MAX = 500;
 const CLEANUP_BATCH = 2000;
 private function get_client_ip() {
$ip = isset($_SERVER['REMOTE_ADDR']) ? $_SERVER['REMOTE_ADDR'] : '0.0.0.0';
$trusted_proxy = filter_var($ip, FILTER_VALIDATE_IP,
 FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE) === false;
if ($trusted_proxy) {
 foreach (array('HTTP_CF_CONNECTING_IP', 'HTTP_X_REAL_IP', 'HTTP_X_FORWARDED_FOR') as $hdr) {
 if (!empty($_SERVER[$hdr])) {
 $candidate = trim(explode(',', $_SERVER[$hdr])[0]);
 if (filter_var($candidate, FILTER_VALIDATE_IP)) {
  return $candidate;
 }
 }
 }
}
return $ip;
 }
 private function check_rate_limit( $ip, $action, $limit, $window = 60 ) {
$key  = 'mlp_rl_' . $action . '_' . md5($ip);
$group = 'mlp_rate';
if ( wp_using_ext_object_cache() ) {
 $hits = (int) wp_cache_get( $key, $group );
 if ( $hits >= $limit ) {
  // Only log at the exact threshold and then every 500 hits (not every 100).
  // Logging every 100 hits under bot load causes cascading DB writes that
  // spike CPU. The exact-limit log is enough for security auditing.
  if ( $hits === $limit || ( $hits % 500 === 0 ) ) {
   $this->log_anomaly( $ip, $action, 'rate_limit_exceeded', $hits );
  }
  return false;
 }
 if ( $hits === 0 ) {
  wp_cache_set( $key, 1, $group, $window );
 } else {
  wp_cache_set( $key, $hits + 1, $group, $window );
 }
 return true;
}
$hits = (int) get_transient( $key );
if ( $hits >= $limit ) {
 // Only log at the exact threshold and every 500 hits (not every 50).
 // Under a sustained bot flood this cut the anomaly-log DB writes by ~90%.
 if ( $hits === $limit || ( $hits % 500 === 0 ) ) {
  $this->log_anomaly( $ip, $action, 'rate_limit_exceeded', $hits );
 }
 return false;
}
if ( $hits === 0 ) {
 set_transient( $key, 1, $window );
} else {
 set_transient( $key, $hits + 1, $window );
}
return true;
 }
 private function validate_code_input( $html = '', $css = '', $js = '' ) {
$total = strlen($html) + strlen($css) + strlen($js);
if ($total > self::MAX_CODE_BYTES) {
 return new WP_Error('code_too_large',
 sprintf('Code exceeds maximum allowed size of %s KB.',
 round(self::MAX_CODE_BYTES / 1024)));
}
foreach (array($html, $css, $js) as $segment) {
 // Use strpos as a fast pre-screen (O(n) string scan, no regex engine overhead).
 // Only invoke the heavier preg_match when '<?' is actually present — on clean
 // user code this means we skip the regex entirely on every request.
 if ( strpos($segment, '<?') !== false && preg_match('/<\?(?:php|=)/i', $segment) ) {
  $this->log_anomaly($this->get_client_ip(), 'code_input', 'php_tag_injection', substr($segment, 0, 100));
  return new WP_Error('invalid_code', 'Submitted code contains disallowed content.');
 }
}
return true;
 }
 private function log_anomaly( $ip, $context, $type, $detail = '' ) {
$safe_detail = $this->redact_pii($detail);
// Combine both IP-masking patterns into a single preg_replace_callback pass
// (one regex compile instead of two) to cut CPU on every log entry.
$masked_ip = preg_replace(
 array(
  '/(\d+\.\d+)\.\d+\.\d+/',
  '/([0-9a-fA-F]{1,4}:[0-9a-fA-F]{1,4}):[0-9a-fA-F:]+/',
 ),
 array( '$1.[redacted]', '$1:[redacted]' ),
 $ip
);
// Always write to PHP error log (synchronous, cheap I/O).
error_log(sprintf('[MLP Security] %s | IP:%s ctx:%s detail:%s',
 sanitize_text_field($type), $masked_ip, sanitize_text_field($context), $safe_detail));
// Static re-entry guard: prevent a recursive flush from triggering another flush
// (e.g. if log_anomaly is called while we're already inside update_option).
static $mlp_flushing = false;
if ( $mlp_flushing ) { return; }
// Buffer DB writes: collect entries in a transient and only flush to the
// persistent option once per 30-second window to avoid a DB write on every event.
$buffer_key = 'mlp_anomaly_buffer';
$buffer = get_transient( $buffer_key );
if ( ! is_array( $buffer ) ) { $buffer = array(); }
$buffer[] = array(
 'time'    => current_time('mysql'),
 'ip'      => $masked_ip,
 'context' => sanitize_text_field($context),
 'type'    => sanitize_text_field($type),
 'detail'  => $safe_detail,
);
set_transient( $buffer_key, $buffer, 30 );
// Flush to option when buffer is large or the flush-lock has expired.
// Only one flush per 30-second window; skip entirely if already flushing.
if ( count( $buffer ) >= 20 || ! get_transient( 'mlp_anomaly_flush_lock' ) ) {
 $mlp_flushing = true;
 set_transient( 'mlp_anomaly_flush_lock', 1, 30 );
 $log = get_option( 'mlp_anomaly_log', array() );
 $log = array_merge( $log, $buffer );
 if ( count( $log ) > self::ANOMALY_LOG_MAX ) {
  $log = array_slice( $log, -self::ANOMALY_LOG_MAX );
 }
 update_option( 'mlp_anomaly_log', $log, false );
 delete_transient( $buffer_key );
 $mlp_flushing = false;
}
 }
