<script>
(function(){
  var cats = [
    ['mlp-manager-readme-header-<?php echo esc_attr($instance_id); ?>',   'mlp-manager-readme-items-<?php echo esc_attr($instance_id); ?>'],
    ['mlp-manager-backups-header-<?php echo esc_attr($instance_id); ?>',  'mlp-manager-backups-items-<?php echo esc_attr($instance_id); ?>'],
    ['mlp-manager-console-header-<?php echo esc_attr($instance_id); ?>',  'mlp-manager-console-items-<?php echo esc_attr($instance_id); ?>'],
    ['mlp-manager-media-header-<?php echo esc_attr($instance_id); ?>',    'mlp-manager-media-items-<?php echo esc_attr($instance_id); ?>'],
    ['mlp-manager-storage-header-<?php echo esc_attr($instance_id); ?>',  'mlp-manager-storage-items-<?php echo esc_attr($instance_id); ?>']
  ];
  document.addEventListener('click', function(e){
    cats.forEach(function(pair){
      var hdr = e.target.closest('#'+pair[0]);
      if(!hdr) return;
      e.stopPropagation();
      var items = document.getElementById(pair[1]);
      var open = hdr.classList.toggle('mlp-open');
      if(items) items.classList.toggle('mlp-open', open);
    });
  });
})();
</script>
