<script>
(function(){
  var wrap = document.querySelector('.mlp-footer-support-wrap');
  if (!wrap) return;
  var btn = wrap.querySelector('.mlp-footer-support-btn');
  var dd = wrap.querySelector('.mlp-footer-support-dropdown');
  btn.addEventListener('click', function(e){
    e.preventDefault();
    e.stopPropagation();
    dd.style.display = dd.style.display === 'none' ? 'block' : 'none';
  });
  document.addEventListener('click', function(e){
    if (!wrap.contains(e.target)) dd.style.display = 'none';
  });
})();
</script>
</div>
<script>
if (typeof window.monacoLoaders === "undefined") {
window.monacoLoaders = [];
}
window.monacoLoaders.push({
instanceId: "<?php echo esc_js($instance_id); ?>",
html: <?php echo json_encode($default_html); ?>,
css: <?php echo json_encode($default_css); ?>,
js: <?php echo json_encode($default_js); ?>,
editorTheme: "<?php echo esc_js($atts['editor_theme']); ?>",
originalDefaults: <?php echo json_encode($original_defaults); ?>,
preprocessors: { html: "html", css: "css", js: "javascript" }
});
// Hard-refresh (Ctrl+F5) safety net: scripts may load out-of-order when cache is bypassed.
// After full page load, check each loader entry and re-trigger init if Monaco didn't mount.
window.addEventListener('load', function() {
  setTimeout(function() {
    if (!window.monacoLoaders || !window.monacoLoaders.length) return;
    window.monacoLoaders.forEach(function(loaderData) {
      var inst = window.monacoInstances && window.monacoInstances[loaderData.instanceId];
      var editorMissing = !inst || !inst.htmlEditor;
      if (editorMissing && typeof initMonacoForInstance === 'function') {
        console.log('[MLP] Hard-refresh recovery: re-initialising', loaderData.instanceId);
        initMonacoForInstance(loaderData);
      }
    });
  }, 600);
});
</script>
