 public function settings_page_content() {
if (!current_user_can('manage_options')) {
 return;
}
// Batch all option reads at the top — avoids repeated DB calls scattered through the HTML.
$s = wp_cache_get( 'mlp_settings_page_opts', 'mlp_options' );
if ( $s === false ) {
 $s = array(
  'height'       => get_option('mlp_default_height', '600px'),
  'title'        => get_option('mlp_default_title', 'Mobile Live Preview'),
  'theme'        => get_option('mlp_default_theme', 'dark'),
  'editor_theme' => get_option('mlp_editor_theme', 'vs-dark'),
  'html'         => get_option('mlp_default_html', ''),
  'css'          => get_option('mlp_default_css', ''),
  'js'           => get_option('mlp_default_js', ''),
  'anomaly_log'  => get_option('mlp_anomaly_log', array()),
 );
 wp_cache_set( 'mlp_settings_page_opts', $s, 'mlp_options', 60 );
}
