<td><?php echo $share_rows > $share_cap * 0.9
? '<span style="color:#d63638;">&#9888; Near cap</span>'
: '<span style="color:#00a32a;">&#10003; OK</span>'; ?></td>
</tr>
</tbody>
</table>
<form method="post" style="margin-top:8px;">
 <?php wp_nonce_field('mlp_run_cleanup_nonce'); ?>
<input type="hidden" name="mlp_run_cleanup" value="1">
<button type="submit" class="button button-secondary">&#9851; Run Cleanup Now</button>
</form>
<!-- Traffic Caps -->
<h3 style="margin-top:24px;">&#128268; Traffic Caps &amp; Limits</h3>
<form method="post" action="options.php">
 <?php settings_fields('mlp_settings_group'); ?>
<table class="form-table" style="max-width:700px;">
<tr>
<th><label for="mlp_share_max_rows"><?php _e('Share Table Row Cap', 'mobile-live-preview'); ?></label></th>
<td>
<input type="number" id="mlp_share_max_rows" name="mlp_share_max_rows"
value="<?php echo esc_attr(get_option('mlp_share_max_rows', self::SHARE_TABLE_MAX_ROWS)); ?>"
min="1000" max="10000000" class="small-text">
<p class="description"><?php _e('Maximum rows in the shared codes table. Oldest rows pruned automatically. Default: 50,000.', 'mobile-live-preview'); ?></p>
</td>
</tr>
</table>
 <?php submit_button(__('Save Traffic Settings', 'mobile-live-preview')); ?>
</form>
<!-- Cron Status -->
<h3 style="margin-top:24px;">&#9201; Scheduled Cron Status</h3>
<table class="widefat" style="max-width:600px;">
<tbody>
<tr>
<td><strong>Hourly cleanup</strong></td>
<td><span style="color:#888;">Removed — AI cache pruned inline. Share table cleanup on deactivation/activation only.</span></td>
</tr>
<tr>
<td><strong>Daily counter reset</strong></td>
<td><?php
echo '<span style="color:#888;">Removed — daily AI cap resets via transient TTL.</span>';
?></td>
</tr>
</tbody>
</table>
<p style="color:#666;font-size:12px;margin-top:6px;"><?php _e('If cron shows "Not scheduled", deactivate and reactivate the plugin to re-register the schedule.', 'mobile-live-preview'); ?></p>
</div>
<?php
 }
