/* Console functions are now in mlp-console.php */
function generateBackupId() {return Math.floor(10000+Math.random()*90000).toString();}
function getBackups() {try {const backups=localStorage.getItem("mlp_backups");return backups?JSON.parse(backups) : {};} catch (e) {console.error("Error reading backups:", e);return {};}}
function saveBackups(backups) {try {localStorage.setItem("mlp_backups", JSON.stringify(backups));try {var bUsed=0;for (var bk in localStorage){if (localStorage.hasOwnProperty(bk)) bUsed += ((localStorage[bk]||"").length+bk.length)*2; }
var bPct=(bUsed/(5*1024*1024))*100;if (bPct >= 80) {if (typeof window.mlpCheckStorageWarn === "function") window.mlpCheckStorageWarn(instanceId);}} catch(e) {}
return true;} catch (e) {console.error("Error saving backups:", e);return false;}}
function createBackup(instanceId, name) {const instances=window.monacoInstances[instanceId];if (!instances || !instances.activeTabId) return null;saveTabData(instanceId, instances.activeTabId);
const tabData=instances.tabs[instances.activeTabId];const backupId=generateBackupId();const timestamp=new Date().toISOString();const backup={id: backupId,name: name,timestamp: timestamp,data: {
html: tabData.html || "",css: tabData.css || "",js: tabData.js || "",preprocessors:{...tabData.preprocessors }}};const backups=getBackups();backups[backupId]=backup;if (saveBackups(backups)) {return backup;}
return null;}
function loadBackup(instanceId, backupId) {const backups=getBackups();const backup=backups[backupId];if (!backup) return false;const instances=window.monacoInstances[instanceId];
if (!instances) return false;const tabId="tab-"+Date.now()+"-"+Math.random().toString(36).substr(2, 9);const tabData={id: tabId,title: "Backup: "+backup.name,emoji: "☁︎",isForked: false,
isReadOnly: false,html: backup.data.html,css: backup.data.css,js: backup.data.js,preprocessors:{...backup.data.preprocessors },active: false};instances.tabs[tabId]=tabData;createTabElement(instanceId, tabId, tabData.title, tabData.emoji, false, false);switchTab(instanceId, tabId);return true;}
function deleteBackup(backupId) {const backups=getBackups();delete backups[backupId];return saveBackups(backups);}
function searchBackups(query) {const backups=getBackups();const results=[];Object.values(backups).forEach(backup => {const searchText=(backup.name+" "+backup.id).toLowerCase();
if (searchText.includes(query.toLowerCase())) {results.push(backup);}});return results.sort((a, b) => new Date(b.timestamp)-new Date(a.timestamp));}
function formatDate(timestamp) {const date=new Date(timestamp);return date.toLocaleDateString()+" "+date.toLocaleTimeString();}
