$("#mlp-backup-modal-"+instanceId).removeClass("active");};window.openBackupWarningModal=function(instanceId) {const name=$("#backup-name-"+instanceId).val().trim();if (!name) {var inp=$("#backup-name-"+instanceId);inp.css({"border-color":"#f44336","box-shadow":"0 0 0 2px rgba(244,67,54,0.25)"});inp.attr("placeholder","\u26a0 Please enter a backup name first!");inp.focus();setTimeout(function(){inp.css({"border-color":"","box-shadow":""});inp.attr("placeholder","Enter a descriptive name...");},2500);return;}
$("#mlp-backup-modal-"+instanceId).removeClass("active");$("#mlp-backup-warning-modal-"+instanceId).addClass("active");};window.closeBackupWarningModal=function(instanceId) {
$("#mlp-backup-warning-modal-"+instanceId).removeClass("active");};window.closeBackupSuccessModal=function(instanceId) {$("#mlp-backup-success-modal-"+instanceId).removeClass("active");};
window.openBackupsListModal=function(instanceId) {$("#mlp-backups-list-modal-"+instanceId).addClass("active");renderBackupsList(instanceId);};window.closeBackupsListModal=function(instanceId) {
$("#mlp-backups-list-modal-"+instanceId).removeClass("active");};function getBackupSize(backup) {const raw=JSON.stringify(backup.data || {});const bytes=new Blob([raw]).size;
if (bytes<1024) return bytes+" B";if (bytes<1024*1024) return (bytes/1024).toFixed(1)+" KB";return (bytes/(1024*1024)).toFixed(2)+" MB";}
function updateBackupSelectionUI(instanceId) {const modal=$("#mlp-backups-list-modal-"+instanceId);const checked=modal.find(".mlp-backup-item-checkbox:checked").length;
const total=modal.find(".mlp-backup-item-checkbox").length;const deleteBtn=$("#mlp-backup-delete-selected-"+instanceId);const selectAll=$("#mlp-backup-select-all-"+instanceId);if (checked>0) {
deleteBtn.show().html("<i class=\"fas fa-trash\"></i> Delete Selected ("+checked+")");} else {deleteBtn.hide();}
selectAll.prop("indeterminate", checked>0 && checked<total);selectAll.prop("checked", total>0 && checked === total);}
function renderBackupsList(instanceId) {const container=$("#mlp-backups-list-"+instanceId);const emptyState=$("#mlp-backups-empty-"+instanceId);const countEl=$("#mlp-backups-count-"+instanceId);const searchQuery=$("#backups-search-"+instanceId).val().trim();
