<span class="mlp-backup-item-date"><i class="fas fa-clock" style="margin-right:3px;opacity:0.7;font-size:0.75rem;"></i>${formatDate(backup.timestamp)}</span>
</div>
</div>
<div class="mlp-backup-item-actions">
<button class="mlp-backup-load-btn" data-backup-id="${backup.id}">
