/* Export to CodePen */
container.on("click", ".mlp-export-codepen-btn", function(e) {
  e.preventDefault(); e.stopPropagation();
  $exportDd.hide();
  var instances = window.monacoInstances && window.monacoInstances[instanceId];
  if (!instances || !instances.activeTabId) return;
  saveTabData(instanceId, instances.activeTabId);
  var tab = instances.tabs[instances.activeTabId];
  if (!tab) return;
  var payload = { html: tab.html||"", css: tab.css||"", js: tab.js||"", editors: "1100" };
  var form = document.createElement("form");
  form.method = "POST"; form.action = "https://codepen.io/pen/define"; form.target = "_blank";
  var inp = document.createElement("input");
  inp.type = "hidden"; inp.name = "data"; inp.value = JSON.stringify(payload);
  form.appendChild(inp); document.body.appendChild(form); form.submit(); document.body.removeChild(form);
  if (typeof showNotification === "function") showNotification(instanceId, "Opening in CodePen…", "success");
});
