  if ($toggle.length) { if (!$toggle.hasClass("mlp-chat-open")) { $toggle.trigger("click"); } }
  else { var $sidebar = $("#mlpChatSidebar"); if ($sidebar.length) { $sidebar.addClass("mlp-chat-open"); $("#mlpChatBackdrop").addClass("mlp-chat-open"); } }
  /* Pre-fill the textarea with the prompt */
  setTimeout(function() {
    var $input = $("#mlpChatInput");
    if ($input.length) {
      $input.val(prompt + ": ");
      $input.trigger("input"); /* auto-resize */
      $input.focus();
      var len = $input.val().length;
      $input[0].setSelectionRange(len, len);
    } else if (typeof window.mlpChatFill === "function") { window.mlpChatFill(prompt + ": "); }
  }, 300);
});

