/* ── Tab drag-to-reorder ── */
(function initTabDragSort(iid){
  var $list=$("#mlp-tabs-list-"+iid);
  var dragSrcId=null, dragSrcEl=null, dragGhost=null;
  function getDragAfterElement(x){
    var tabs=$list.find(".mlp-tab").not(".mlp-tab-drag-active").toArray();
    return tabs.reduce(function(closest,child){
      var box=child.getBoundingClientRect();
      var offset=x-(box.left+box.width/2);
      if(offset<0&&offset>closest.offset){return{offset:offset,element:child};}
      return closest;
    },{offset:Number.NEGATIVE_INFINITY}).element;
  }
  $list.on("mousedown",".mlp-tab",function(e){
    if($(e.target).closest(".mlp-tab-close,.mlp-tab-rename").length)return;
    var $tab=$(this);
    var startX=e.clientX,startY=e.clientY,moved=false,dragging=false;
    var tabId=$tab.data("tab-id");
    function onMouseMove(ev){
      var dx=ev.clientX-startX,dy=ev.clientY-startY;
      if(!moved&&Math.sqrt(dx*dx+dy*dy)>5){moved=true;}
      if(!moved)return;
      if(!dragging){
        dragging=true;
        dragSrcId=tabId;
        dragSrcEl=$tab[0];
        $tab.addClass("mlp-tab-drag-active");
        dragGhost=$tab.clone().css({
          position:"fixed",pointerEvents:"none",opacity:"0.75",zIndex:999999,
          width:$tab.outerWidth()+"px",height:$tab.outerHeight()+"px",
          margin:0,transform:"rotate(2deg) scale(1.04)",
          boxShadow:"0 8px 24px rgba(0,0,0,0.5)",
          border:"1px solid #4dccff",background:"linear-gradient(135deg,#4dccff 0%,#2a8fd6 100%)"
        }).appendTo("body");
      }
      dragGhost.css({left:(ev.clientX-dragGhost.outerWidth()/2)+"px",top:(ev.clientY-dragGhost.outerHeight()/2-8)+"px"});
      $list.find(".mlp-tab-drag-over").removeClass("mlp-tab-drag-over");
      var after=getDragAfterElement(ev.clientX);
      if(after){$(after).addClass("mlp-tab-drag-over");}
    }
    function onMouseUp(ev){
      $(document).off("mousemove.mlpdrag mouseup.mlpdrag");
      if(dragGhost){dragGhost.remove();dragGhost=null;}
      $list.find(".mlp-tab-drag-active").removeClass("mlp-tab-drag-active");
      $list.find(".mlp-tab-drag-over").removeClass("mlp-tab-drag-over");
      if(!dragging||!dragSrcId)return;
      var after=getDragAfterElement(ev.clientX);
      var $src=$list.find(".mlp-tab[data-tab-id=\""+dragSrcId+"\"]");
      if(after){$src.insertBefore(after);}else{$list.append($src);}
      dragSrcId=null;dragSrcEl=null;dragging=false;
    }
    $(document).on("mousemove.mlpdrag",onMouseMove).on("mouseup.mlpdrag",onMouseUp);
  });
  /* Touch support */
  $list.on("touchstart",".mlp-tab",function(e){
    if($(e.target).closest(".mlp-tab-close,.mlp-tab-rename").length)return;
    var $tab=$(this),tabId=$tab.data("tab-id");
    var t0=e.originalEvent.touches[0];
    var startX=t0.clientX,startY=t0.clientY,moved=false,dragging=false;
    function onTouchMove(ev){
      var t=ev.originalEvent.touches[0];
      var dx=t.clientX-startX,dy=t.clientY-startY;
      if(!moved&&Math.sqrt(dx*dx+dy*dy)>8){moved=true;}
      if(!moved)return;
      ev.preventDefault();
      if(!dragging){
        dragging=true;dragSrcId=tabId;
        $tab.addClass("mlp-tab-drag-active");
        dragGhost=$tab.clone().css({
          position:"fixed",pointerEvents:"none",opacity:"0.75",zIndex:999999,
          width:$tab.outerWidth()+"px",height:$tab.outerHeight()+"px",
          margin:0,transform:"rotate(2deg) scale(1.04)",
          boxShadow:"0 8px 24px rgba(0,0,0,0.5)",
          border:"1px solid #4dccff",background:"linear-gradient(135deg,#4dccff 0%,#2a8fd6 100%)"
        }).appendTo("body");
      }
      dragGhost.css({left:(t.clientX-dragGhost.outerWidth()/2)+"px",top:(t.clientY-dragGhost.outerHeight()/2-8)+"px"});
      $list.find(".mlp-tab-drag-over").removeClass("mlp-tab-drag-over");
      var after=getDragAfterElement(t.clientX);
      if(after){$(after).addClass("mlp-tab-drag-over");}
    }
    function onTouchEnd(ev){
      $tab.off("touchmove.mlpdrag touchend.mlpdrag");
      if(dragGhost){dragGhost.remove();dragGhost=null;}
      $list.find(".mlp-tab-drag-active").removeClass("mlp-tab-drag-active");
      $list.find(".mlp-tab-drag-over").removeClass("mlp-tab-drag-over");
      if(!dragging||!dragSrcId)return;
      var t=ev.originalEvent.changedTouches[0];
      var after=getDragAfterElement(t.clientX);
      var $src=$list.find(".mlp-tab[data-tab-id=\""+dragSrcId+"\"]");
      if(after){$src.insertBefore(after);}else{$list.append($src);}
      dragSrcId=null;dragging=false;
    }
    $tab.on("touchmove.mlpdrag",{passive:false},onTouchMove).on("touchend.mlpdrag",onTouchEnd);
  });
})(instanceId);
}
