function mlpForceImportant(css){try{return css.replace(/(:[^;{}\"\']+?)(;|\s*(?=}))/g,function(m,decl,end){if(/!important\s*$/.test(decl.trim()))return m;return decl.trim()+\' !important\'+end;});}catch(e){return css;}}
function mlpBuildPreviewHTML(compiledHTML, compiledCSS, compiledJS){var userHeadContent="";var userBodyContent=compiledHTML;var userBodyAttrs="";var hasHead=/<head[\s>]/i.test(compiledHTML);var hasBody=/<body[\s>]/i.test(compiledHTML);var hasHtml=/<html[\s>]/i.test(compiledHTML);if(hasHead||hasBody||hasHtml){var headMatch=compiledHTML.match(/<head[^>]*>([\s\S]*?)<\/head>/i);if(headMatch){userHeadContent=headMatch[1];}var bodyMatch=compiledHTML.match(/<body([^>]*)>([\s\S]*?)<\/body>/i);if(bodyMatch){userBodyAttrs=bodyMatch[1]||"";userBodyContent=bodyMatch[2];}else if(hasBody){var bodyStart=compiledHTML.match(/<body([^>]*)>([\s\S]*)/i);if(bodyStart){userBodyAttrs=bodyStart[1]||"";userBodyContent=bodyStart[2].replace(/<\/body>\s*(<\/html>)?\s*$/i,"");}}else{userBodyContent=compiledHTML.replace(/<!DOCTYPE[^>]*>/i,"").replace(/<\/?html[^>]*>/gi,"").replace(/<head[^>]*>[\s\S]*?<\/head>/i,"");}}var fullHTML="<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Mobile Preview</title>\n"+userHeadContent+"\n<style>\nbody{margin:0;padding:0;}\n"+compiledCSS+"\n</style>\n</head>\n<body"+userBodyAttrs+">\n"+userBodyContent+"\n<script>\ntry {"+compiledJS+"} catch(err){console.error(\"JS Error:\",err);}\n<\/script>\n</body>\n</html>";return fullHTML;}
async function updatePreview(instanceId) {if (MLP_SECURITY.isKillSwitchActive()) return;const instances=window.monacoInstances[instanceId];if (!instances || instances.isPreviewUpdating || !instances.htmlEditor) return;instances.isPreviewUpdating=true;const container=$("#"+instanceId);
const previewLoader=$("#mlp-preview-loader-main-"+instanceId);const previewIndicator=$("#mlp-preview-indicator-main-"+instanceId+" .mlp-preview-emoji");const previewFrame=$("#mlp-preview-frame-main-"+instanceId);previewLoader.addClass("active");previewIndicator.addClass("active");try {
const htmlCode=instances.htmlEditor?instances.htmlEditor.getValue() : "";const cssCode=instances.cssEditor?instances.cssEditor.getValue() : "";
const jsCode=instances.jsEditor?instances.jsEditor.getValue() : "";var codeSizeErr=MLP_SECURITY.validateCodeSize(htmlCode, cssCode, jsCode);if (codeSizeErr) {
showNotification(instanceId, codeSizeErr, "error");instances.isPreviewUpdating=false;previewLoader.removeClass("active");previewIndicator.removeClass("active");return;}
let compiledHTML=htmlCode;let compiledCSS=cssCode;let compiledJS=jsCode;const tabData=instances.tabs[instances.activeTabId];
const preprocessors=tabData?tabData.preprocessors :{html: "html", css: "css", js: "javascript" };try {compiledHTML=await compilePreprocessor("html", htmlCode, preprocessors.html);} catch (e) {showNotification(instanceId, "HTML Error: "+e.message, "error");}
try {compiledCSS=await compilePreprocessor("css", cssCode, preprocessors.css);} catch (e) {showNotification(instanceId, "CSS Error: "+e.message, "error");}
try {compiledJS=await compilePreprocessor("js", jsCode, preprocessors.js);} catch (e) {showNotification(instanceId, "JS Error: "+e.message, "error");}
const fullHTML=mlpBuildPreviewHTML(compiledHTML, compiledCSS, compiledJS);const iframe=previewFrame[0];const iframeDoc=iframe.contentDocument || iframe.contentWindow.document;MLP_SECURITY.armIframeTimer(instanceId, iframe);
var _previewDone=false;function _clearPreviewLoader(){if(_previewDone)return;_previewDone=true;previewLoader.removeClass("active");previewIndicator.removeClass("active");instances.isPreviewUpdating=false;}
iframe.onload=function(){MLP_SECURITY.clearIframeTimer(instanceId);_clearPreviewLoader();};iframeDoc.open();iframeDoc.write(fullHTML);iframeDoc.close();
setTimeout(_clearPreviewLoader,80);} catch (error) {console.error("Preview update error:", error);MLP_SECURITY.clearIframeTimer(instanceId);showNotification(instanceId, "Preview update failed", "error");instances.isPreviewUpdating=false;previewLoader.removeClass("active");previewIndicator.removeClass("active");}}
