  var iid=$(this).data(\'instance\');
  mlpGearCloseAll();
  var inst=window.monacoInstances&&window.monacoInstances[iid];
  if(!inst)return;
  var tab=inst.activeTab||\'html\';
  var editor=tab===\'html\'?inst.htmlEditor:tab===\'css\'?inst.cssEditor:inst.jsEditor;
  if(editor){var code=editor.getValue();if(navigator.clipboard){navigator.clipboard.writeText(code).then(function(){if(typeof showNotification===\'function\')showNotification(iid,\'Code copied ✓\',\'success\');});}else{var ta=document.createElement(\'textarea\');ta.value=code;document.body.appendChild(ta);ta.select();document.execCommand(\'copy\');document.body.removeChild(ta);if(typeof showNotification===\'function\')showNotification(iid,\'Code copied ✓\',\'success\');}}
});

/* ── Word Wrap toggle ── */
$(document).on(\'click\',\'.mlp-settings-wrap-btn\',function(e){
  e.stopPropagation();
  var iid=$(this).data(\'instance\');
  var inst=window.monacoInstances&&window.monacoInstances[iid];
  if(!inst)return;
  var editors=[inst.htmlEditor,inst.cssEditor,inst.jsEditor].filter(Boolean);
  var current=editors[0]?editors[0].getRawOptions().wordWrap:\'off\';
  var next=current===\'on\'?\'off\':\'on\';
  editors.forEach(function(ed){ed.updateOptions({wordWrap:next});});
  $(this).find(\'.mlp-settings-wrap-label\').text(\'Word Wrap: \'+(next===\'on\'?\'On\':\'Off\'));
  var $w=$(this).closest(\'.mlp-editor-settings-wrap\');
  var s=mlpReadEditorUI($w);s.wordWrap=(next===\'on\');mlpSave(iid,s);
});

/* ── Minimap toggle ── */
$(document).on(\'click\',\'.mlp-settings-minimap-btn\',function(e){
  e.stopPropagation();
  var iid=$(this).data(\'instance\');
  var inst=window.monacoInstances&&window.monacoInstances[iid];
  if(!inst)return;
  var editors=[inst.htmlEditor,inst.cssEditor,inst.jsEditor].filter(Boolean);
  var current=editors[0]?editors[0].getRawOptions().minimap:{enabled:true};
  var next=!(current&&current.enabled!==false);
