  if(!inst)return;
  var tab=inst.activeTab||\'html\';
  var tabLabel=tab.toUpperCase();
  var pp=inst.activeTabId&&inst.tabs[inst.activeTabId]?inst.tabs[inst.activeTabId].preprocessors||{}:{};
  var ppKey=pp[tab]||(tab===\'js\'?\'javascript\':tab);
  var label=ppKey.charAt(0).toUpperCase()+ppKey.slice(1);
  if(typeof mlpGetPreproLabel===\'function\'){var info=mlpGetPreproLabel(tab,ppKey);label=info.label;}
  $w.find(\'.mlp-settings-format-label\').text(\'Format \'+label);
  $w.find(\'.mlp-settings-prepro-label\').text(\'Prepro of \'+tabLabel);
  $w.find(\'.mlp-settings-copy-label\').text(\'Copy \'+tabLabel);
  $w.find(\'.mlp-settings-clear-label\').text(\'Clear \'+tabLabel);
  var tabTitle=inst.activeTabId&&inst.tabs[inst.activeTabId]?((inst.tabs[inst.activeTabId].emoji||\'\')+\' \'+(inst.tabs[inst.activeTabId].title||tab)).trim():tabLabel;
  var ppHtml=pp[\'html\']||\'html\';var ppCss=pp[\'css\']||\'css\';var ppJs=pp[\'js\']||\'javascript\';
  var lHtml=typeof mlpGetPreproLabel===\'function\'?mlpGetPreproLabel(\'html\',ppHtml).label:ppHtml;
  var lCss=typeof mlpGetPreproLabel===\'function\'?mlpGetPreproLabel(\'css\',ppCss).label:ppCss;
  var lJs=typeof mlpGetPreproLabel===\'function\'?mlpGetPreproLabel(\'js\',ppJs).label:ppJs;
  var preproStr=\'(\'+lHtml+\' \'+lCss+\' \'+lJs+\')\';
  $w.find(\'.mlp-settings-export-label\').text(\'Export \'+label);
  $w.find(\'.mlp-settings-exportzip-label\').text(\'Export .zip \'+preproStr);
  var editor=tab===\'html\'?inst.htmlEditor:tab===\'css\'?inst.cssEditor:inst.jsEditor;
  if(editor){
    var ww=editor.getRawOptions().wordWrap;
