document.addEventListener("visibilitychange", function() {
  if (!document.hidden && window.monacoInstances) {
    Object.keys(window.monacoInstances).forEach(function(iid) {
      var inst = window.monacoInstances[iid];
      if (!inst) return;
      // Layout all normal editors
      [inst.htmlEditor, inst.cssEditor, inst.jsEditor].forEach(function(ed) {
        if (ed) { try { ed.layout(); } catch(e) {} }
      });
      // Layout fullscreen editors too
      [inst.fullscreenHtmlEditor, inst.fullscreenCssEditor, inst.fullscreenJsEditor].forEach(function(ed) {
        if (ed) { try { ed.layout(); } catch(e) {} }
      });
      // On mobile, re-check if editors have zero height and force a re-layout after a tick
      if (window.matchMedia && window.matchMedia(\'(max-width: 767px)\').matches) {
        setTimeout(function() {
          [inst.htmlEditor, inst.cssEditor, inst.jsEditor].forEach(function(ed) {
            if (ed) { try { ed.layout(); } catch(e) {} }
          });
        }, 300);
      }
    });
  }
});
